import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"Namespace Registry","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/30_data/50_namespace_registry.md","filePath":"10_core/30_data/50_namespace_registry.md"}'),i={name:"10_core/30_data/50_namespace_registry.md"};function l(d,e,n,s,c,u){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="namespace-registry" tabindex="-1">Namespace Registry <a class="header-anchor" href="#namespace-registry" aria-label="Permalink to &quot;Namespace Registry&quot;">​</a></h1><p>Status: Active<br> Version: 1.0</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>QiOS uses a governed namespace registry to route work, artifacts, and workspace containers.</p><p>Namespace codes are routing allocations for governed containers of work, not identifiers for every person, contact, login, or raw database row.</p><p>Current active doctrine uses these routes to organize QiNexus work, QiAccess Start documentation, and related local operational containers. Old tenant/platform language below is reference-only unless a future shared-container model is explicitly activated.</p><p>Relational identity and namespace routing are separate concerns:</p><ul><li>relational IDs answer: &quot;what is this?&quot;</li><li>namespace codes answer: &quot;where does this work belong?&quot;</li></ul><hr><h2 id="core-doctrine" tabindex="-1">Core Doctrine <a class="header-anchor" href="#core-doctrine" aria-label="Permalink to &quot;Core Doctrine&quot;">​</a></h2><ol><li>Namespace codes are container routes, not universal entity identifiers.</li><li>Contacts, users, clients, vendors, and organizations must exist as relational records first.</li><li>Namespace allocation occurs only when a governed workspace, matter, project, legacy tenant container, archive block, or other approved routed container is required.</li><li>Namespace bands are finite, explicit, and registry-controlled.</li><li>No new top-level band may be created without blueprint update or ADR approval.</li><li>Namespace aliases may exist for legacy interpretation, but full canonical names remain authoritative in blueprint doctrine.</li></ol><hr><h2 id="structural-syntax" tabindex="-1">Structural Syntax <a class="header-anchor" href="#structural-syntax" aria-label="Permalink to &quot;Structural Syntax&quot;">​</a></h2><ul><li><code>####AAA</code> = structural node</li><li><code>####AAA.###</code> = subgroup, child route, bucket, or artifact route</li></ul><p>Examples:</p><ul><li><code>0300LGL</code></li><li><code>0330LGL.010</code></li><li><code>5120TNT</code></li><li><code>5441MAT.020</code></li></ul><hr><h2 id="naming-rules" tabindex="-1">Naming Rules <a class="header-anchor" href="#naming-rules" aria-label="Permalink to &quot;Naming Rules&quot;">​</a></h2><h3 id="structural-nodes" tabindex="-1">Structural Nodes <a class="header-anchor" href="#structural-nodes" aria-label="Permalink to &quot;Structural Nodes&quot;">​</a></h3><p><code>####AAA_Label_Name</code></p><h3 id="artifact-files" tabindex="-1">Artifact Files <a class="header-anchor" href="#artifact-files" aria-label="Permalink to &quot;Artifact Files&quot;">​</a></h3><p><code>####AAA.###_YYYY-MM-DD_title_detail.ext</code></p><hr><h2 id="decimal-rules" tabindex="-1">Decimal Rules <a class="header-anchor" href="#decimal-rules" aria-label="Permalink to &quot;Decimal Rules&quot;">​</a></h2><ul><li><code>.000</code> = base/default/index under node</li><li><code>.010</code>, <code>.020</code>, <code>.030</code> = grouping buckets</li><li><code>.011-.019</code> = descendants/items under <code>.010</code></li><li><code>.021-.029</code> = descendants/items under <code>.020</code></li></ul><p>Trailing zeroes are reserved for grouping buckets unless explicitly used as an index node.</p><hr><h2 id="rollup-rule" tabindex="-1">Rollup Rule <a class="header-anchor" href="#rollup-rule" aria-label="Permalink to &quot;Rollup Rule&quot;">​</a></h2><p>Descendants roll up numerically.</p><p>Example:</p><p><code>0330LGL.011</code> -&gt; <code>0330LGL.010</code> -&gt; <code>0330LGL</code> -&gt; <code>0300LGL</code></p><hr><h2 id="allocation-rule" tabindex="-1">Allocation Rule <a class="header-anchor" href="#allocation-rule" aria-label="Permalink to &quot;Allocation Rule&quot;">​</a></h2><p>Namespace blocks are assigned only to governed containers requiring durable routing.</p><p>Approved allocation targets include:</p><ul><li>system roots</li><li>official bands</li><li>governed workspaces</li><li>matters</li><li>projects</li><li>archival containers</li><li>approved operational partitions</li></ul><p>Namespace blocks must NOT be assigned to:</p><ul><li>every contact</li><li>every portal login</li><li>every CRM row</li><li>every raw record</li><li>every message or event</li><li>every client unless a governed workspace exists</li></ul><hr><h2 id="registry-bands" tabindex="-1">Registry Bands <a class="header-anchor" href="#registry-bands" aria-label="Permalink to &quot;Registry Bands&quot;">​</a></h2><h3 id="_0000–1999-—-global-shared-constitutional-bands" tabindex="-1">0000–1999 — Global / Shared Constitutional Bands <a class="header-anchor" href="#_0000–1999-—-global-shared-constitutional-bands" aria-label="Permalink to &quot;0000–1999 — Global / Shared Constitutional Bands&quot;">​</a></h3><p>Reserved for stable top-level routing bands.</p><h3 id="_2000–4999-—-future-shared-domain-expansion" tabindex="-1">2000–4999 — Future Shared Domain Expansion <a class="header-anchor" href="#_2000–4999-—-future-shared-domain-expansion" aria-label="Permalink to &quot;2000–4999 — Future Shared Domain Expansion&quot;">​</a></h3><p>Reserved for future major approved domains.</p><h3 id="_5000-7999-workspace-allocation-bands" tabindex="-1">5000-7999 - Workspace Allocation Bands <a class="header-anchor" href="#_5000-7999-workspace-allocation-bands" aria-label="Permalink to &quot;5000-7999 - Workspace Allocation Bands&quot;">​</a></h3><p>Reserved for matter, project, governed workspace, or equivalent routed allocation. Tenant wording here is legacy/future only.</p><h3 id="_8000–8999-—-lab-sandbox" tabindex="-1">8000–8999 — Lab / Sandbox <a class="header-anchor" href="#_8000–8999-—-lab-sandbox" aria-label="Permalink to &quot;8000–8999 — Lab / Sandbox&quot;">​</a></h3><p>Reserved for experimental and non-canonical routing.</p><h3 id="_9000–9999-—-archive-legacy" tabindex="-1">9000–9999 — Archive / Legacy <a class="header-anchor" href="#_9000–9999-—-archive-legacy" aria-label="Permalink to &quot;9000–9999 — Archive / Legacy&quot;">​</a></h3><p>Reserved for deprecated, frozen, migrated, or cold-storage routing.</p><hr><h2 id="canonical-band-manifest" tabindex="-1">Canonical Band Manifest <a class="header-anchor" href="#canonical-band-manifest" aria-label="Permalink to &quot;Canonical Band Manifest&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Range</th><th>Code</th><th>Canonical Name</th><th>Role</th></tr></thead><tbody><tr><td>0000</td><td>ROOT</td><td>Root</td><td>system root</td></tr><tr><td>0100</td><td>KBS</td><td>Knowledge Base</td><td>doctrine, references, templates</td></tr><tr><td>0200</td><td>VLT</td><td>Vault</td><td>records, entities, durable holdings</td></tr><tr><td>0300</td><td>LGL</td><td>Legal</td><td>legal work and litigation support</td></tr><tr><td>0400</td><td>FIN</td><td>Finance</td><td>financial routing and financial artifacts</td></tr><tr><td>0500</td><td>OPS</td><td>Operations</td><td>tasks, projects, requests, schedules</td></tr><tr><td>0600</td><td>SYS</td><td>Systems</td><td>architecture, schemas, automations, deployments</td></tr><tr><td>0700</td><td>HUM</td><td>Human</td><td>household, support, relationships, routines</td></tr><tr><td>0800</td><td>HLT</td><td>Health</td><td>logs, care, regulation, recovery</td></tr><tr><td>0900</td><td>MED</td><td>Media</td><td>writing, publishing, campaigns, assets</td></tr><tr><td>1000</td><td>CRM</td><td>CRM</td><td>leads, active clients, engagements, closeout</td></tr><tr><td>1100</td><td>TPL</td><td>Templates</td><td>prompts, forms, packets, boilerplates</td></tr><tr><td>1200</td><td>REF</td><td>Reference</td><td>laws, cases, snapshots, citations</td></tr><tr><td>8000</td><td>LAB</td><td>Lab</td><td>experiments and prototypes</td></tr><tr><td>9000</td><td>ARC</td><td>Archive</td><td>legacy and frozen materials</td></tr></tbody></table><hr><h2 id="workspace-allocation-bands" tabindex="-1">Workspace Allocation Bands <a class="header-anchor" href="#workspace-allocation-bands" aria-label="Permalink to &quot;Workspace Allocation Bands&quot;">​</a></h2><p>Workspace allocations must use controlled registry assignment from the 5000–7999 range.</p><p>Recommended patterns:</p><ul><li><code>5xxxTNT</code> = legacy/future tenant workspace alias</li><li><code>54xxMAT</code> = matter workspace</li><li><code>56xxPRJ</code> = project workspace</li><li><code>58xxORG</code> = organization-specific governed workspace</li></ul><p>These are routing classes, not relational identity classes.</p><hr><h2 id="alias-policy" tabindex="-1">Alias Policy <a class="header-anchor" href="#alias-policy" aria-label="Permalink to &quot;Alias Policy&quot;">​</a></h2><p>Abbreviated legacy codes may be recognized as aliases for interpretation only.</p><p>Examples:</p><ul><li><code>ARC</code> -&gt; <code>QiArchive</code> alias only</li><li><code>ALY</code> -&gt; <code>QiAlly</code> alias only</li><li><code>CAS</code> -&gt; <code>QiCase</code> alias only</li></ul><p>Aliases are not canonical replacements for official blueprint names.</p><hr><h2 id="adhd-safe-structural-constraint" tabindex="-1">ADHD-Safe Structural Constraint <a class="header-anchor" href="#adhd-safe-structural-constraint" aria-label="Permalink to &quot;ADHD-Safe Structural Constraint&quot;">​</a></h2><ul><li>maximum structural folder depth = 3 levels from root</li><li>use decimal buckets before adding new folders</li><li>avoid sibling overlap</li><li>organize by function, not theme</li></ul><hr><h2 id="compliance-requirement" tabindex="-1">Compliance Requirement <a class="header-anchor" href="#compliance-requirement" aria-label="Permalink to &quot;Compliance Requirement&quot;">​</a></h2><p>All namespace allocations must be:</p><ul><li>registry-valid</li><li>unique within scope</li><li>mapped to an approved owner type</li><li>documented in the allocation registry</li><li>consistent with blueprint band doctrine</li></ul>',72)])])}const m=a(i,[["render",l]]);export{h as __pageData,m as default};
